(function(){"use strict";function escHtml(s){return String(s==null?"":s).replace(/[&<>"]/g,function(c){return{"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;"}[c]})}function buildBragCardHtml(opts){opts=opts||{};var gameTitle=opts.gameTitle||"this game";var who=opts.fromName||"";var stats=[];String(opts.stats||"").split("|").forEach(function(seg){if(!seg)return;var p=seg.split("~");if(p.length<2||!p[1])return;stats.push({label:p[0],value:p[1],badge:p[2]==="b"})});var poster=opts.img||opts.gameImage||"";var cap=opts.caption||"Beat that.";var statsHtml="";if(stats.length){var primary=stats[0],rest=stats.slice(1);statsHtml+=primary.badge?'<div class="brag-live-primary"><div class="brag-live-stat brag-live-stat--badge"><div class="v">'+escHtml(primary.value)+'</div><div class="k">'+escHtml(primary.label)+"</div></div></div>":'<div class="brag-live-primary"><div class="brag-live-stat brag-live-stat--primary"><div class="k">'+escHtml(primary.label)+'</div><div class="v">'+escHtml(primary.value)+"</div></div></div>";if(rest.length){statsHtml+='<div class="brag-live-substrip">'+rest.map(function(s){return s.badge?'<div class="brag-live-stat brag-live-stat--badge"><div class="v">'+escHtml(s.value)+'</div><div class="k">'+escHtml(s.label)+"</div></div>":'<div class="brag-live-stat brag-live-stat--sub"><div class="v">'+escHtml(s.value)+'</div><div class="k">'+escHtml(s.label)+"</div></div>"}).join("")+"</div>"}}var posterStyle=poster?` style="--brag-poster:url('`+poster+`');--brag-poster-opacity:1;"`:"";return'<div class="brag-live-card"'+posterStyle+'><div class="brag-live-shot"'+(poster?"":" hidden")+">"+(poster?'<img src="'+poster+'" alt="">':"")+`</div><div class="brag-live-meta"><div class="brag-live-brand"><span class="brag-live-logo"><img src="https://www.wgplayground.com/public/new/images/logo-square.svg" alt="" onerror="this.style.display='none'"></span><span class="brag-live-wordmark"><b>WG</b><span>Playground</span></span></div><div class="brag-live-iplayed">`+(who?escHtml(who.split(" ")[0]).toUpperCase()+" PLAYED":"I JUST PLAYED")+'</div><div class="brag-live-title">'+escHtml(gameTitle)+'</div><div class="brag-live-stats">'+statsHtml+'</div><div class="brag-live-caption">'+escHtml(cap)+'</div><div class="brag-live-foot"><b>wgplayground.com</b><span>Accept to challenge them back \u2192</span></div></div></div>'}function freshButton(id){var el=document.getElementById(id);if(!el)return null;var clone=el.cloneNode(true);el.parentNode.replaceChild(clone,el);return clone}function showBrag(d){var overlay=document.getElementById("challengeArrival");if(!overlay)return;d=d||{};if(overlay.parentNode!==document.body)document.body.appendChild(overlay);var slot=document.getElementById("challengeArrivalBrag");if(slot){slot.innerHTML=buildBragCardHtml({stats:d.stats,caption:d.caption,fromName:d.fromName,gameTitle:d.gameTitle,img:d.img,gameImage:d.gameImage});slot.removeAttribute("hidden")}var t=document.getElementById("challengeArrivalTitle");if(t)t.innerHTML=d.fromName?"<strong>"+escHtml(String(d.fromName).split(" ")[0])+"</strong> threw down a challenge":"You\u2019ve been challenged";var sub=document.getElementById("challengeArrivalSub");if(sub)sub.setAttribute("hidden","");function hide(){overlay.classList.remove("is-open");setTimeout(function(){overlay.setAttribute("hidden","")},280)}function accept(){if(window.wgpTrack)window.wgpTrack.track("challenge_accept",{challenge_id:d.id||d.hash,game_url:d.url});hide();function focusPlayer(){var ifr=document.getElementById("playerIframe");if(!ifr)return false;try{ifr.scrollIntoView({behavior:"smooth",block:"center"})}catch(e){}try{ifr.focus()}catch(e){}try{if(ifr.contentWindow)ifr.contentWindow.postMessage({type:"wgp-launch"},"https://play.wgplayground.com")}catch(e){}return true}if(d.url){var target=String(d.url).split("#")[0].split("?")[0];var here=location.origin+location.pathname;if(target===here){focusPlayer();return}try{window.location.href=target+"#play";return}catch(e){}}focusPlayer()}var acc=freshButton("challengeArrivalAccept");var lat=freshButton("challengeArrivalLater");var cls=freshButton("challengeArrivalClose");if(acc)acc.addEventListener("click",accept);if(lat)lat.addEventListener("click",hide);if(cls)cls.addEventListener("click",hide);overlay.removeAttribute("hidden");requestAnimationFrame(function(){overlay.classList.add("is-open")})}window.wgpChallengeArrival=window.wgpChallengeArrival||{};window.wgpChallengeArrival.showBrag=showBrag})();
